import { useState } from 'react'
import { useNavigate, Link } from 'react-router-dom'
import { Container, Title, TextInput, PasswordInput, Button, Stack, Text, Alert } from '@mantine/core'
import { graphql } from 'gql.tada'
import { useMutation } from '@/lib/graphql'
import { useAuthStore } from '@/stores/authStore'

const LoginMutation = graphql(`
  mutation Login($input: LoginInput!) {
    login(input: $input) {
      token
      user {
        id
        email
        displayName
      }
    }
  }
`)

export function Login() {
  const navigate = useNavigate()
  const setAuth = useAuthStore((s) => s.setAuth)
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [, executeMutation] = useMutation(LoginMutation)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    const result = await executeMutation({ input: { email, password } })
    if (result.error) {
      setError(result.error.graphQLErrors[0]?.message ?? 'Login failed')
      return
    }

    const { token, user } = result.data.login
    setAuth(token, user)
    navigate('/')
  }

  return (
    <Container size="xs" py="xl">
      <Stack gap="lg">
        <Title order={2}>Login</Title>

        {error && (
          <Alert color="red" variant="light">
            {error}
          </Alert>
        )}

        <form onSubmit={handleSubmit}>
          <Stack gap="md">
            <TextInput
              label="Email"
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.currentTarget.value)}
            />
            <PasswordInput
              label="Password"
              required
              value={password}
              onChange={(e) => setPassword(e.currentTarget.value)}
            />
            <Button type="submit">Login</Button>
          </Stack>
        </form>

        <Text fz="sm" c="dimmed">
          Don&apos;t have an account?{' '}
          <Text component={Link} to="/register" c="brand.6" inherit>
            Register
          </Text>
        </Text>
      </Stack>
    </Container>
  )
}

import { useNavigate } from 'react-router-dom'
import { Container, Title, Text, SimpleGrid, Card, Group, Button, Stack } from '@mantine/core'
import { Search, BookmarkPlus, FileText, Mic } from 'lucide-react'
import { useAuthStore } from '@/stores/authStore'

const FEATURES = [
  {
    icon: BookmarkPlus,
    title: 'Bookmarks',
    description: 'Save URLs with automatic page content extraction and metadata.',
  },
  {
    icon: FileText,
    title: 'Notes',
    description: 'Capture quick text notes with tags and categories.',
  },
  {
    icon: Mic,
    title: 'Voice Notes',
    description: 'Record voice memos with automatic transcription.',
  },
  {
    icon: Search,
    title: 'Semantic Search',
    description: 'Find anything with full-text and AI-powered semantic search.',
  },
]

export function Home() {
  const navigate = useNavigate()
  const token = useAuthStore((s) => s.token)

  return (
    <Container size="md" py="xl">
      <Stack gap="xl">
        <div>
          <Title order={1} c="brand.8">
            Your second brain
          </Title>
          <Text c="dimmed" fz="lg" mt="xs">
            Capture thoughts, bookmarks, and voice notes. Find them instantly with semantic search.
          </Text>
        </div>

        <Group gap="sm">
          <Button
            leftSection={<Search size={16} />}
            onClick={() => navigate('/search')}
          >
            Search
          </Button>
          {token ? (
            <Button
              variant="light"
              leftSection={<BookmarkPlus size={16} />}
              onClick={() => navigate('/capture')}
            >
              Capture
            </Button>
          ) : (
            <Button variant="light" onClick={() => navigate('/login')}>
              Login to capture
            </Button>
          )}
        </Group>

        <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="lg">
          {FEATURES.map((feature) => (
            <Card key={feature.title} shadow="sm" padding="lg" radius="md" withBorder>
              <Group gap="sm" mb="xs">
                <feature.icon size={20} />
                <Text fw={600}>{feature.title}</Text>
              </Group>
              <Text fz="sm" c="dimmed">
                {feature.description}
              </Text>
            </Card>
          ))}
        </SimpleGrid>
      </Stack>
    </Container>
  )
}

